/* ============================================================
   3. BOROUGH BOUNDARY DATA
   We fetch the official NYC borough boundary GeoJSON directly
   from NYC Open Data using their Geospatial API export endpoint.

   Dataset: Borough Boundaries
   Link:    https://data.cityofnewyork.us/City-Government/Borough-Boundaries/gthc-hcne
   Format:  GeoJSON export — returns WGS84 coordinates (lat/lng)
            compatible with Leaflet out of the box.

   If the fetch fails (e.g. no network), we fall back to a set
   of simplified hand-drawn polygons so the map still works.
============================================================ */

/* NYC Open Data GeoJSON export URL.
   Dataset ID: gthc-hcne (Borough Boundaries)
   The ?method=export&type=GeoJSON endpoint returns the full
   boundary polygons in WGS84 — no conversion needed. */
const BOROUGH_API =
  'https://data.cityofnewyork.us/api/geospatial/gthc-hcne' +
  '?method=export&type=GeoJSON';

/* Each borough gets a distinct color for its fill and border.
   Kept at very low opacity so they don't compete with the data dots.
   The boro_name field in the NYC Open Data GeoJSON is title-cased. */
const BOROUGH_COLORS = {
  "Manhattan":    "#4a90d9",  /* blue   */
  "Brooklyn":     "#27ae60",  /* green  */
  "Queens":       "#e67e22",  /* orange */
  "Bronx":        "#8e44ad",  /* purple */
  "Staten Island":"#c0392b"   /* red    */
};

