/* ============================================================
   4. CONSTANTS & LAYER GROUPS
============================================================ */
const NYC_CENTER   = [40.710, -73.985]; // approx centre of NYC
const DEFAULT_ZOOM = 11;
const BUFFER_MI    = 0.5;               // 0.5-mile proximity threshold
const BUFFER_M     = BUFFER_MI * 1609;  // convert to metres for Leaflet

/* Leaflet LayerGroups — each holds one category of map shapes.
   We add/remove entire groups when switching between steps.
   lgBorough is special: it is never removed from the map. */
const lgBorough  = L.layerGroup(); // borough boundary polygons (always on)
const lgNYCHA    = L.layerGroup(); // all NYCHA development dots
const lgBuffers  = L.layerGroup(); // 0.5-mile buffer circles
const lgCenters  = L.layerGroup(); // evacuation center markers
const lgGap      = L.layerGroup(); // NYCHA outside buffer (red)
const lgPriority = L.layerGroup(); // priority area rectangles

let map;
let gapCount    = 0; // how many NYCHA developments have an access gap
let currentStep = 0; // which story step is currently on screen


/* ============================================================
   5. UTILITY FUNCTIONS
============================================================ */

/* ── Haversine distance ──────────────────────────────────────
   Calculates the straight-line distance between two lat/lng
   points in miles. Used to check whether a NYCHA development
   falls within BUFFER_MI miles of any evacuation center.
──────────────────────────────────────────────────────────── */
function distanceMiles(lat1, lon1, lat2, lon2) {
  const R     = 3958.8;
  const toRad = deg => deg * Math.PI / 180;
  const dLat  = toRad(lat2 - lat1);
  const dLon  = toRad(lon2 - lon1);
  const a =
    Math.sin(dLat / 2) ** 2 +
    Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) *
    Math.sin(dLon / 2) ** 2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
}

/* Returns true if the NYCHA development is within BUFFER_MI
   miles of at least one evacuation center */
function isWithinBuffer(nycha) {
  return evacData.some(c =>
    distanceMiles(nycha.latitude, nycha.longitude, c.latitude, c.longitude) <= BUFFER_MI
  );
}


/* ============================================================
   6. MAP INITIALISATION
   Creates the Leaflet map, adds the CartoDB basemap tile layer,
   and kicks off the async borough boundary fetch so it loads
   in the background while the rest of the page initialises.
============================================================ */
function initMap() {
  map = L.map('map', {
    center:      NYC_CENTER,
    zoom:        DEFAULT_ZOOM,
    zoomControl: true
  });

  /* CartoDB Positron — a clean, minimal light basemap that lets
     the data colors stand out without visual clutter */
  L.tileLayer(
    'https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png',
    {
      attribution:
        '&copy; <a href="https://www.openstreetmap.org/">OpenStreetMap</a> ' +
        'contributors &copy; <a href="https://carto.com/">CARTO</a>',
      maxZoom: 18
    }
  ).addTo(map);

  /* Borough layer group goes on the map immediately so it sits
     underneath all other data layers once the GeoJSON arrives */
  lgBorough.addTo(map);

  /* Fetch borough boundaries asynchronously.
     The rest of the page doesn't wait for this — NYCHA dots
     and the scrollytelling start working straight away. */
  loadBoroughBoundaries();
}


/* ── Fetch borough boundaries from NYC Open Data ─────────────
   Tries the official GeoJSON export endpoint first.
   Falls back to the simplified embedded polygons if that fails
   (e.g. network unavailable or request blocked).
──────────────────────────────────────────────────────────── */
async function loadBoroughBoundaries() {
  /* Shared function to render whichever GeoJSON we end up with */
  function renderBorough(geojson) {
    L.geoJSON(geojson, {

      /* Style each borough polygon with its own color.
         The gthc-hcne dataset uses the field name "boro_name". */
      style: function(feature) {
        const name  = feature.properties.boro_name
                   || feature.properties.BoroName
                   || feature.properties.name
                   || '';
        const color = BOROUGH_COLORS[name] || '#888888';
        return {
          fillColor:   color,
          fillOpacity: 0.07,   /* very light — just a hint of color */
          color:       color,  /* border matches fill */
          weight:      1.8
        };
      },

      /* Bind a hover tooltip showing the borough name */
      onEachFeature: function(feature, layer) {
        const name = feature.properties.boro_name
                  || feature.properties.BoroName
                  || feature.properties.name
                  || '';
        if (name) {
          layer.bindTooltip(name, {
            permanent:  false,
            direction:  'center',
            className:  'borough-tooltip'
          });
        }
      }

    }).addTo(lgBorough);
  }

  try {
    /* Attempt to fetch the real borough boundaries from NYC Open Data.
       Dataset: Borough Boundaries (Water Areas Included)
       https://data.cityofnewyork.us/City-Government/Borough-Boundaries/7t3b-ywvw */
    const res     = await fetch(BOROUGH_API);
    const geojson = await res.json();
    renderBorough(geojson);
    console.log('Borough boundaries loaded from NYC Open Data.');

  } catch (err) {
    /* If the fetch fails, silently fall back to the embedded simplified polygons */
    console.warn('Borough fetch failed — using fallback polygons.', err);
    renderBorough(BOROUGH_FALLBACK);
  }
}


/* ============================================================
   7. BUILDING ALL MAP LAYERS
   Creates every Leaflet shape from the embedded data arrays.
   Called once at startup. Borough boundaries are loaded
   separately (and asynchronously) in loadBoroughBoundaries().
============================================================ */
function buildAllLayers() {


  /* ── All NYCHA developments — blue dots (step 1) ────────────
     One circleMarker per development.
     Clicking a dot shows the name and borough in a popup.
  ──────────────────────────────────────────────────────────── */
  nychaData.forEach(d => {
    lgNYCHA.addLayer(
      L.circleMarker([d.latitude, d.longitude], {
        radius:      5,
        fillColor:   '#457b9d',  /* steel blue */
        color:       '#1a2744',  /* dark navy outline */
        weight:      0.5,
        fillOpacity: 0.82
      }).bindPopup(`<strong>${d.name}</strong><br>Borough: ${d.borough}`)
    );
  });


  /* ── Evacuation centers + 0.5-mile buffer circles (steps 2–3)
     For each evacuation center we draw:
       1. A dashed orange buffer circle (804 m ≈ 0.5 miles)
       2. A glowing orange dot for the center itself
  ──────────────────────────────────────────────────────────── */
  evacData.forEach(c => {

    /* Buffer circle */
    lgBuffers.addLayer(
      L.circle([c.latitude, c.longitude], {
        radius:      BUFFER_M,
        fillColor:   '#f4a261',
        fillOpacity: 0.10,
        color:       '#e76f51',
        weight:      1.2,
        dashArray:   '5 5'
      })
    );

    /* Glowing center marker using a custom HTML div icon */
    const icon = L.divIcon({
      html: `<div style="
        width:13px; height:13px;
        background:#e76f51;
        border:2px solid #fff;
        border-radius:50%;
        box-shadow:0 0 8px rgba(231,111,81,0.7)
      "></div>`,
      iconSize:   [13, 13],
      iconAnchor: [6, 6],
      className:  ''
    });

    lgCenters.addLayer(
      L.marker([c.latitude, c.longitude], { icon })
       .bindPopup(`<strong>🏫 ${c.name}</strong><br>${c.address}`)
    );
  });


  /* ── NYCHA access-gap dots — red (steps 2–4) ─────────────────
     Re-draws NYCHA developments that are NOT within 0.5 miles
     of any evacuation center. These represent the "access gap"
     — developments that are exposed to risk but far from help.
  ──────────────────────────────────────────────────────────── */
  nychaData.forEach(d => {
    if (isWithinBuffer(d)) return; /* this one is covered — skip it */
    gapCount++;                    /* count developments with a gap */

    lgGap.addLayer(
      L.circleMarker([d.latitude, d.longitude], {
        radius:      6,
        fillColor:   '#c1121f',  /* urgent red */
        color:       '#7a0619',
        weight:      0.8,
        fillOpacity: 0.88
      }).bindPopup(
        `<strong>${d.name}</strong><br>
         Borough: ${d.borough}<br>
         <span style="color:#c1121f">⚠ Outside 0.5-mile buffer</span>`
      )
    );
  });

  /* Now that gapCount is computed, fill in the stat callout */
  updateStatBox();


  /* ── Priority area rectangles (step 4) ───────────────────────
     Approximate bounding boxes for the four highest-priority
     geographic clusters identified in the analysis.
  ──────────────────────────────────────────────────────────── */
  [
    {
      label:  'South Bronx',
      bounds: [[40.808, -73.940], [40.842, -73.888]],
      note:   'High NYCHA density + limited evacuation center proximity'
    },
    {
      label:  'Southern Brooklyn',
      bounds: [[40.568, -74.025], [40.622, -73.935]],
      note:   'Coastal exposure + access gaps (Coney Island / Red Hook)'
    },
    {
      label:  'Southeast Queens',
      bounds: [[40.590, -73.810], [40.682, -73.738]],
      note:   'Farther from centralised evacuation infrastructure'
    },
    {
      label:  'Staten Island North Shore',
      bounds: [[40.492, -74.270], [40.558, -74.120]],
      note:   'Waterfront exposure + limited transit options'
    }
  ].forEach(area => {
    lgPriority.addLayer(
      L.rectangle(area.bounds, {
        color:       '#023e8a',
        weight:      2,
        fillColor:   '#023e8a',
        fillOpacity: 0.12,
        dashArray:   '6 4'
      }).bindPopup(
        `<strong>🔵 Priority area: ${area.label}</strong><br>
         <em>${area.note}</em>`
      )
    );
  });
}


/* ============================================================
   8. SHOWING / HIDING LAYERS BY STEP
   Called by IntersectionObserver when a story step scrolls
   into view. Removes all data layers then adds only those
   relevant to the current step.
   Note: lgBorough is NOT in the removal list — it stays on
   the map at all times as a permanent background layer.
============================================================ */
function showStep(step) {
  if (step === currentStep) return;
  currentStep = step;

  /* Remove all data layers (borough stays) */
  [lgNYCHA, lgBuffers, lgCenters, lgGap, lgPriority].forEach(lg => {
    if (map.hasLayer(lg)) map.removeLayer(lg);
  });

  /* Add the right layers and fly to the appropriate view */
  switch (step) {

    case 1:
      /* All NYCHA developments — citywide overview */
      lgNYCHA.addTo(map);
      map.flyTo(NYC_CENTER, DEFAULT_ZOOM, { duration: 1.3 });
      break;

    case 2:
      /* NYCHA + evacuation centers + buffers + access-gap highlights */
      lgNYCHA.addTo(map);
      lgBuffers.addTo(map);
      lgCenters.addTo(map);
      lgGap.addTo(map);
      map.flyTo(NYC_CENTER, DEFAULT_ZOOM, { duration: 1.3 });
      break;

    case 3:
      /* Zoom in on South Brooklyn to show the access gap pattern */
      lgBuffers.addTo(map);
      lgCenters.addTo(map);
      lgGap.addTo(map);
      map.flyTo([40.635, -73.975], 12, { duration: 1.4 });
      break;

    case 4:
      /* Access-gap dots + priority area rectangles, citywide view */
      lgGap.addTo(map);
      lgPriority.addTo(map);
      map.flyTo(NYC_CENTER, DEFAULT_ZOOM, { duration: 1.3 });
      break;
  }

  updateLegend(step);
}


/* ============================================================
   9. UPDATING THE LEGEND
   Injects HTML into the map legend panel to match the layers
   currently visible for each step.
============================================================ */
function updateLegend(step) {
  const el = document.getElementById('map-legend');

  const legends = {

    1:
      `<span class="legend-title">NYCHA Developments</span>
       <div class="legend-item">
         <div class="legend-dot" style="background:#457b9d"></div>
         <span>NYCHA development</span>
       </div>
       <div class="legend-item">
         <div class="legend-dot" style="background:#4a90d9;border-radius:2px;opacity:0.6"></div>
         <span>Borough boundary</span>
       </div>`,

    2:
      `<span class="legend-title">Evacuation Access</span>
       <div class="legend-item">
         <div class="legend-dot" style="background:#c1121f"></div>
         <span>NYCHA — outside 0.5 mi buffer</span>
       </div>
       <div class="legend-item">
         <div class="legend-dot" style="background:#457b9d"></div>
         <span>NYCHA — within buffer</span>
       </div>
       <div class="legend-item">
         <div class="legend-dot" style="background:#e76f51"></div>
         <span>Evacuation center</span>
       </div>
       <div class="legend-item">
         <div class="legend-dash" style="border-color:#e76f51"></div>
         <span>0.5-mile buffer</span>
       </div>`,

    3:
      `<span class="legend-title">Access Gap (zoomed)</span>
       <div class="legend-item">
         <div class="legend-dot" style="background:#c1121f"></div>
         <span>NYCHA outside buffer</span>
       </div>
       <div class="legend-item">
         <div class="legend-dot" style="background:#e76f51"></div>
         <span>Evacuation center</span>
       </div>
       <div class="legend-item">
         <div class="legend-dash" style="border-color:#e76f51"></div>
         <span>0.5-mile buffer</span>
       </div>`,

    4:
      `<span class="legend-title">Planning Priority</span>
       <div class="legend-item">
         <div class="legend-dot" style="background:#023e8a;border-radius:2px"></div>
         <span>High-priority areas</span>
       </div>
       <div class="legend-item">
         <div class="legend-dot" style="background:#c1121f"></div>
         <span>NYCHA outside buffer</span>
       </div>`
  };

  el.innerHTML = legends[step] || '';
}


/* ============================================================
   10. STAT BOX
   After gapCount is computed in buildAllLayers(), this updates
   the statistics callout inside Step 2's text card.
============================================================ */
function updateStatBox() {
  const box = document.getElementById('stat-box-gap');
  if (!box) return;
  const pct = Math.round((gapCount / nychaData.length) * 100);
  box.innerHTML =
    `<span class="stat-number">${gapCount}</span>` +
    `NYCHA developments — ${pct}% of those mapped — ` +
    `are more than 0.5 miles from a hurricane evacuation center.`;
}


/* ============================================================
   11. SCROLLYTELLING — IntersectionObserver
   Watches each .step element. When one enters the viewport's
   middle zone, it becomes "active" (its left border turns red)
   and showStep(n) is called to update the map accordingly.
============================================================ */
function setupScrollytelling() {
  const steps = document.querySelectorAll('.step');

  const observer = new IntersectionObserver(
    entries => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          const n = parseInt(entry.target.dataset.step, 10);
          /* Remove active class from all steps, add to this one */
          steps.forEach(s => s.classList.remove('is-active'));
          entry.target.classList.add('is-active');
          showStep(n);
        }
      });
    },
    /* rootMargin shrinks the trigger zone so the map updates
       only when the step card is roughly centred on screen */
    { rootMargin: '-20% 0px -40% 0px', threshold: 0 }
  );

  steps.forEach(s => observer.observe(s));
}


/* ============================================================
   12. ENTRY POINT
   Everything starts here. DOMContentLoaded ensures the HTML
   is fully parsed before we touch any DOM elements.
============================================================ */
document.addEventListener('DOMContentLoaded', () => {
  initMap();             // 1. create map + add borough layer
  buildAllLayers();      // 2. build all data layers from embedded arrays
  document.getElementById('loading-overlay').classList.add('hidden'); // 3. hide loader
  showStep(1);           // 4. activate step 1
  setupScrollytelling(); // 5. start watching scroll position
});